(1, 5, 3, 'quiz', 'daily_life', 'חידון בית ספר', '{"questions":[{"question":"How do you say מורה in English?","options":["Student","Teacher","Friend","Book"],"correct":1,"emoji":"👩‍🏫","explanation_he":"Teacher = מורה!"},{"question":"What letter does King start with?","options":["L","M","K","N"],"correct":2,"emoji":"👑","explanation_he":"King מתחיל באות K!"},{"question":"How do you say ספר?","options":["Pencil","Class","Book","Write"],"correct":2,"emoji":"📚","explanation_he":"Book = ספר!"},{"question":"How do you say ללמוד?","options":["Read","Write","Play","Learn"],"correct":3,"emoji":"🧠","explanation_he":"Learn = ללמוד!"},{"question":"What letter does Medal start with?","options":["K","L","N","M"],"correct":3,"emoji":"🏅","explanation_he":"Medal מתחיל באות M!"},{"question":"How do you say חבר?","options":["Teacher","Enemy","Friend","Class"],"correct":2,"emoji":"🤝","explanation_he":"Friend = חבר!"},{"question":"What do you use to write?","options":["Book","Pencil","Teacher","Class"],"correct":1,"emoji":"✏️","explanation_he":"Pencil = עיפרון!"},{"question":"How do you say לקרוא?","options":["Write","Run","Read","Speak"],"correct":2,"emoji":"👓","explanation_he":"Read = לקרוא!"}],"timer_seconds":25,"speed_bonus":true}'::jsonb, 80, 20),

