(1, 6, 3, 'quiz', 'daily_life', 'חידון אוכל', '{"questions":[{"question":"How do you say לחם in English?","options":["Cake","Bread","Milk","Egg"],"correct":1,"emoji":"🍞","explanation_he":"Bread = לחם!"},{"question":"What do you drink when thirsty?","options":["Cake","Pizza","Water","Bread"],"correct":2,"emoji":"💧","explanation_he":"Water = מים!"},{"question":"How do you say תפוח?","options":["Banana","Orange","Apple","Egg"],"correct":2,"emoji":"🍎","explanation_he":"Apple = תפוח!"},{"question":"Which comes from a cow?","options":["Egg","Bread","Banana","Milk"],"correct":3,"emoji":"🥛","explanation_he":"Milk = חלב — בא מפרה!"},{"question":"How do you say עוגה?","options":["Pizza","Bread","Cake","Egg"],"correct":2,"emoji":"🎂","explanation_he":"Cake = עוגה!"},{"question":"Which is yellow and long?","options":["Apple","Banana","Egg","Pizza"],"correct":1,"emoji":"🍌","explanation_he":"Banana = בננה — צהובה וארוכה!"},{"question":"How do you say ביצה?","options":["Milk","Bread","Apple","Egg"],"correct":3,"emoji":"🥚","explanation_he":"Egg = ביצה!"},{"question":"How do you say פיצה?","options":["Cake","Bread","Pizza","Banana"],"correct":2,"emoji":"🍕","explanation_he":"Pizza = פיצה — אותו דבר כמעט!"}],"timer_seconds":25,"speed_bonus":false}'::jsonb, 80, 20),

