-- ROUND 7: Advanced Football
(1, 7, 1, 'words', 'football', 'עמדות בכדורגל', '{"words":[{"english":"Goalkeeper","hebrew":"שוער","emoji":"🧤"},{"english":"Defender","hebrew":"בלם","emoji":"🛡️"},{"english":"Midfielder","hebrew":"קשר","emoji":"🔄"},{"english":"Striker","hebrew":"חלוץ","emoji":"⚡"},{"english":"Referee","hebrew":"שופט","emoji":"🟨"},{"english":"Captain","hebrew":"קפטן","emoji":"🏅"},{"english":"Score","hebrew":"לכבוש","emoji":"🎯"},{"english":"Penalty","hebrew":"פנדל","emoji":"⚽"}]}'::jsonb, 75, 18),

(1, 7, 2, 'listening', 'football', 'שמע וזהה — כדורגל', '{"listening_items":[{"text":"The goalkeeper saves the ball!","hebrew":"השוער מציל את הכדור!","options":["The goalkeeper saves","The striker scores","The referee stops","The captain runs"],"correct":0,"emoji":"🧤"},{"text":"The striker scores a goal!","hebrew":"החלוץ כובש שער!","options":["The defender blocks","The striker scores a goal","The midfielder passes","The referee whistles"],"correct":1,"emoji":"⚡"},{"text":"The referee shows a yellow card","hebrew":"השופט מציג כרטיס צהוב","options":["The captain protests","The referee shows a yellow card","The player falls","The team wins"],"correct":1,"emoji":"🟨"},{"text":"The captain leads the team","hebrew":"הקפטן מוביל את הקבוצה","options":["The captain leads the team","The striker runs fast","The defender kicks","The goalkeeper jumps"],"correct":0,"emoji":"🏅"}],"timer_seconds":30}'::jsonb, 75, 18),

(1, 7, 3, 'quiz', 'football', 'חידון כדורגל מתקדם', '{"questions":[{"question":"Who protects the goal?","options":["Striker","Midfielder","Goalkeeper","Referee"],"correct":2,"emoji":"🧤","explanation_he":"Goalkeeper = שוער — מגן על השער!"},{"question":"How do you say חלוץ?","options":["Defender","Goalkeeper","Referee","Striker"],"correct":3,"emoji":"⚡","explanation_he":"Striker = חלוץ — הוא כובש שערים!"},{"question":"How do you say שופט?","options":["Captain","Referee","Midfielder","Player"],"correct":1,"emoji":"🟨","explanation_he":"Referee = שופט!"},{"question":"What is a penalty?","options":["A yellow card","A free kick from the spot","A corner kick","A throw-in"],"correct":1,"emoji":"⚽","explanation_he":"Penalty = פנדל — בעיטה ממרחק קבוע!"},{"question":"How do you say קפטן?","options":["Coach","Referee","Captain","Striker"],"correct":2,"emoji":"🏅","explanation_he":"Captain = קפטן — מנהיג הקבוצה!"},{"question":"What does Midfielder mean?","options":["שוער","חלוץ","בלם","קשר"],"correct":3,"emoji":"🔄","explanation_he":"Midfielder = קשר — משחק באמצע!"},{"question":"How do you say לכבוש שער?","options":["Pass the ball","Score a goal","Save the ball","Stop the game"],"correct":1,"emoji":"🎯","explanation_he":"Score a goal = לכבוש שער!"},{"question":"Who wears gloves in football?","options":["Striker","Referee","Midfielder","Goalkeeper"],"correct":3,"emoji":"🧤","explanation_he":"The Goalkeeper = השוער לובש כפפות!"},{"question":"How do you say בלם?","options":["Midfielder","Striker","Goalkeeper","Defender"],"correct":3,"emoji":"🛡️","explanation_he":"Defender = בלם — עוצר את החלוצים!"},{"question":"What color card means you are out?","options":["Yellow","Green","Blue","Red"],"correct":3,"emoji":"🟥","explanation_he":"Red card = כרטיס אדום — יוצאים מהמגרש!"}],"timer_seconds":20,"speed_bonus":true}'::jsonb, 90, 25),

(1, 7, 4, 'conversation', 'football', 'ביום המשחק', '{"dialogue":[{"speaker":"coach","text":"Today we play the final! Are you ready?","hebrew":"היום אנחנו משחקים גמר! אתה מוכן?","emoji":"🏆"},{"speaker":"child","hebrew":"כן! אני מוכן לגמר!","options":["Yes! I am ready for the final!","No, I am tired","I want to go home"],"correct":0},{"speaker":"coach","text":"You are our striker today. Score a goal!","hebrew":"אתה החלוץ שלנו היום. כבוש שער!","emoji":"⚡"},{"speaker":"child","hebrew":"אכבוש שער בשביל הקבוצה!","options":["I will score for the team!","I prefer to defend","I am scared"],"correct":0},{"speaker":"coach","text":"The referee blows the whistle. The game starts!","hebrew":"השופט שורק. המשחק מתחיל!","emoji":"🟨"},{"speaker":"child","hebrew":"בוא נצא לנצח!","options":["Let us go and win!","Wait a moment","I need water"],"correct":0},{"speaker":"coach","text":"GOAL! You scored! We are champions!","hebrew":"שער! כבשת! אנחנו אלופים!","emoji":"🏆"},{"speaker":"child","hebrew":"אנחנו ניצחנו! אנחנו הכי טובים!","options":["We won! We are the best!","Lucky shot","The referee helped us"],"correct":0}]}'::jsonb, 90, 25),

