(1, 8, 3, 'quiz', 'daily_life', 'חידון רגשות ויומיום', '{"questions":[{"question":"How do you say שמח in English?","options":["Sad","Angry","Happy","Tired"],"correct":2,"emoji":"😊","explanation_he":"Happy = שמח!"},{"question":"You did not sleep — how do you feel?","options":["Happy","Hungry","Scared","Tired"],"correct":3,"emoji":"😴","explanation_he":"Tired = עייף — לא ישנת מספיק!"},{"question":"How do you say כועס?","options":["Happy","Sad","Proud","Angry"],"correct":3,"emoji":"😠","explanation_he":"Angry = כועס!"},{"question":"You did not eat all day — how do you feel?","options":["Proud","Hungry","Happy","Surprised"],"correct":1,"emoji":"🤤","explanation_he":"Hungry = רעב!"},{"question":"How do you say גאה?","options":["Scared","Tired","Proud","Angry"],"correct":2,"emoji":"🦁","explanation_he":"Proud = גאה — כשעושים משהו טוב!"},{"question":"Something scary happens — how do you feel?","options":["Happy","Proud","Scared","Surprised"],"correct":2,"emoji":"😨","explanation_he":"Scared = מפחד!"},{"question":"How do you say עצוב?","options":["Angry","Sad","Tired","Hungry"],"correct":1,"emoji":"😢","explanation_he":"Sad = עצוב!"},{"question":"A surprise party for you — how do you feel?","options":["Angry","Tired","Sad","Surprised"],"correct":3,"emoji":"😲","explanation_he":"Surprised = מופתע!"},{"question":"You won the championship — how do you feel?","options":["Sad","Scared","Tired","Proud"],"correct":3,"emoji":"🏆","explanation_he":"Proud = גאה — כמו שאנחנו גאים בך!"},{"question":"Your best friend moved away — how do you feel?","options":["Happy","Surprised","Sad","Angry"],"correct":2,"emoji":"😢","explanation_he":"Sad = עצוב — זה בסדר להרגיש ככה!"}],"timer_seconds":25,"speed_bonus":false}'::jsonb, 100, 30),

(1, 8, 4, 'conversation', 'daily_life', 'איך אתה מרגיש?', '{"dialogue":[{"speaker":"coach","text":"Hey! How are you feeling today?","hebrew":"היי! איך אתה מרגיש היום?","emoji":"😊"},{"speaker":"child","hebrew":"אני מרגיש מצוין!","options":["I am feeling great!","I am sad","I do not know"],"correct":0},{"speaker":"coach","text":"Are you happy to be here?","hebrew":"אתה שמח להיות כאן?","emoji":"😊"},{"speaker":"child","hebrew":"כן! אני מאוד שמח!","options":["Yes! I am very happy!","No, I am tired","I am hungry"],"correct":0},{"speaker":"coach","text":"Are you tired from the lesson?","hebrew":"אתה עייף מהשיעור?","emoji":"😴"},{"speaker":"child","hebrew":"לא! אני מוכן לעוד!","options":["No! I am ready for more!","Yes, I want to sleep","A little bit"],"correct":0},{"speaker":"coach","text":"Are you proud of what you learned?","hebrew":"אתה גאה במה שלמדת?","emoji":"🦁"},{"speaker":"child","hebrew":"כן! אני גאה מאוד!","options":["Yes! I am very proud!","Not really","I forgot everything"],"correct":0}]}'::jsonb, 100, 30)

